using Microsoft.EntityFrameworkCore;using Microsoft.Extensions.DependencyInjection;using Microsoft.Extensions.Hosting;using Microsoft.Extensions.Logging;using Todos.Domain;
namespace Todos.Persistence.Seed;/** <summary>Todo seeder.</summary> */ public static class TodosSeeder{/** <summary>Seeds once.</summary> */ public static async Task SeedAsync(TodosDbContext db,CancellationToken ct){if(await db.Items.AnyAsync(ct))return;var today=DateOnly.FromDateTime(DateTime.UtcNow);for(var i=0;i<10;i++){var item=TodoItem.Create($"مهمة تجريبية {i+1}",today.AddDays(i+1),(TodoPriority)(i%4),null,today).Value;if(i%3==0)item.ChangeStatus(TodoStatus.InProgress);if(i%5==0)item.ChangeStatus(TodoStatus.Done);db.Items.Add(item);}await db.SaveChangesAsync(ct);}}
/** <summary>Seed hosted service.</summary> */ public sealed class TodosSeedHostedService(IServiceProvider services,ILogger<TodosSeedHostedService> logger):IHostedService{/** <inheritdoc/> */ public async Task StartAsync(CancellationToken ct){try{using var scope=services.CreateScope();await TodosSeeder.SeedAsync(scope.ServiceProvider.GetRequiredService<TodosDbContext>(),ct);logger.LogInformation("Todos seed completed.");}catch(Exception ex){logger.LogWarning(ex,"Todos seed skipped.");}}/** <inheritdoc/> */ public Task StopAsync(CancellationToken ct)=>Task.CompletedTask;}
